class PayrollProcessingService {
    void processMonthlyPayroll(YearMonth payPeriod) {
        List<Employee> activeEmployees = findActiveEmployeesForPayPeriod(payPeriod);
        List<PayrollEntry> payrollEntries = calculatePayrollForAllEmployees(activeEmployees, payPeriod);
        applyDeductionsToAllEntries(payrollEntries);
        submitPayrollEntriesToPaymentProcessor(payrollEntries);
        recordPayrollCompletionInAuditLog(payPeriod, payrollEntries.size());
    }
}
